parameters.functionCode:
const data = $json.body[0] || {};
const weekStart = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000);
const weekEnd = new Date();

const summary = {
  total_entries: data.total_entries || 0,
  total_amount: data.total_amount || 0,
  days_logged: data.days_logged || 0,
  categories: data.categories || [],
  missed_days: 7 - (data.days_logged || 0),
  week_start: weekStart.toLocaleDateString('zh-TW'),
  week_end: weekEnd.toLocaleDateString('zh-TW'),
  top_category: data.top_category,
  average_daily: (data.total_amount / (data.days_logged || 1)).toFixed(2),
  insights: []
};

// Generate insights
if (summary.missed_days > 0) {
  summary.insights.push(`本週缺少 ${summary.missed_days} 天記帳`);
}

if (summary.total_entries > 0) {
  summary.insights.push(`本週共記 ${summary.total_entries} 筆，總金額 $${summary.total_amount}`);
}

if (summary.top_category) {
  summary.insights.push(`主要支出類別: ${summary.top_category}`);
}

return summary;

